  font-size: 14px;
  font-weight: bold;
  margin-bottom: 4px;
}
.calendar-indicator {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
}
.data-dot {
  background-color: #67C23A;
}
.strategy-dot {
  background-color: #409EFF;
}
.signal-count {
  font-size: 10px;
  color: #E6A23C;
}
</style>
