<script setup>
import { ref, onMounted } from 'vue'
import { getStocks, getStockDaily } from '../api/stock.js'

const stocks = ref([])
const total = ref(0)
const currentPage = ref(1)
const pageSize = ref(20)
const loading = ref(false)
const searchQuery = ref('')

const detailVisible = ref(false)
const detailLoading = ref(false)
const selectedStock = ref(null)
const dailyData = ref([])

const loadStocks = async () => {
  loading.value = true
  try {
    const res = await getStocks({
      page: currentPage.value,
      page_size: pageSize.value,
      search: searchQuery.value || undefined
    })
    stocks.value = res.data || []
    total.value = res.total || 0
  } catch (e) {
    console.error('获取股票列表失败:', e)
  }
  loading.value = false
}

const handleSearch = () => {
  currentPage.value = 1
  loadStocks()
}

const handleSizeChange = (val) => {
  pageSize.value = val
  loadStocks()
}

const handleCurrentChange = (val) => {
  currentPage.value = val
  loadStocks()
}

const viewDetail = async (stock) => {
  selectedStock.value = stock
  detailVisible.value = true
  detailLoading.value = true
  try {
    const res = await getStockDaily(stock.stock_code)
    dailyData.value = res.data || []
  } catch (e) {
    console.error('获取日线数据失败:', e)
  }
  detailLoading.value = false
}

const priceFormatter = (row, col, val) => {
  return val ? parseFloat(val).toFixed(2) : '-'
}

onMounted(() => {
  loadStocks()
})
</script>
